Please audit this GraphQL schema for over-permissive nullability:

type Query {
  user(id: ID!): User
  users: [User]
}

type User {
  id: ID
  email: String
  orders: [Order]
  profile: Profile
}

type Order {
  id: ID
  total: Float
  items: [OrderItem]
}

type OrderItem {
  id: ID
  quantity: Int
  product: Product
}

type Product {
  id: ID
  name: String
  price: Float
}

type Profile {
  bio: String
  avatarUrl: String
}
